// Define target cities to scrape
// Rotate through these to build your prospect list

const targetCities = [
  // Tier 1: High-value metros
  { city: 'Phoenix', state: 'AZ', priority: 1 },
  { city: 'Houston', state: 'TX', priority: 1 },
  { city: 'Dallas', state: 'TX', priority: 1 },
  { city: 'Las Vegas', state: 'NV', priority: 1 },
  { city: 'Miami', state: 'FL', priority: 1 },
  { city: 'Atlanta', state: 'GA', priority: 1 },
  { city: 'Denver', state: 'CO', priority: 1 },
  { city: 'San Antonio', state: 'TX', priority: 1 },

  // Tier 2: Growing markets
  { city: 'Austin', state: 'TX', priority: 2 },
  { city: 'Nashville', state: 'TN', priority: 2 },
  { city: 'Charlotte', state: 'NC', priority: 2 },
  { city: 'Orlando', state: 'FL', priority: 2 },
  { city: 'Tampa', state: 'FL', priority: 2 },
  { city: 'Raleigh', state: 'NC', priority: 2 },
  { city: 'Jacksonville', state: 'FL', priority: 2 },

  // Tier 3: Secondary markets (less competition)
  { city: 'Tucson', state: 'AZ', priority: 3 },
  { city: 'Oklahoma City', state: 'OK', priority: 3 },
  { city: 'Albuquerque', state: 'NM', priority: 3 },
  { city: 'Memphis', state: 'TN', priority: 3 },
  { city: 'Louisville', state: 'KY', priority: 3 }
];

// Get today's city (rotate daily)
const dayOfYear = Math.floor((Date.now() - new Date(new Date().getFullYear(), 0, 0)) / (1000 * 60 * 60 * 24));
const cityIndex = dayOfYear % targetCities.length;
const todaysCity = targetCities[cityIndex];

return {
  json: {
    searchQuery: `HVAC companies in ${todaysCity.city}, ${todaysCity.state}`,
    city: todaysCity.city,
    state: todaysCity.state,
    priority: todaysCity.priority,
    searchDate: new Date().toISOString()
  }
};

// Extract and filter HVAC companies
const results = $input.first().json.results || [];
const cityData = $('Get Target City').first().json;

const prospects = results.map(place => {
  // Extract rating info
  const rating = place.rating || 0;
  const reviewCount = place.user_ratings_total || 0;

  // Ideal prospect: 3.5-4.5 stars (growing but has pain points)
  let ratingScore = 0;
  if (rating >= 3.5 && rating <= 4.5) ratingScore = 100;
  else if (rating > 4.5) ratingScore = 60; // Too good, might not need help
  else if (rating >= 3.0) ratingScore = 80; // Struggling, needs help
  else ratingScore = 40; // Too low, might be failing

  // Review count indicates business size
  let sizeScore = 0;
  if (reviewCount >= 50 && reviewCount <= 500) sizeScore = 100; // Sweet spot
  else if (reviewCount > 500) sizeScore = 70; // Big company, harder to close
  else if (reviewCount >= 20) sizeScore = 80; // Small but established
  else sizeScore = 50; // Very small

  return {
    placeId: place.place_id,
    name: place.name,
    address: place.formatted_address,
    rating: rating,
    reviewCount: reviewCount,
    ratingScore: ratingScore,
    sizeScore: sizeScore,
    prospectScore: Math.round((ratingScore + sizeScore) / 2),
    city: cityData.city,
    state: cityData.state,
    searchDate: cityData.searchDate,
    status: 'new'
  };
}).filter(p => p.prospectScore >= 60); // Only keep decent prospects

// Sort by prospect score
prospects.sort((a, b) => b.prospectScore - a.prospectScore);

return prospects.map(p => ({ json: p }));

// Enrich prospect with contact details and pain point analysis
const details = $input.first().json.result || {};
const prospectData = $('Loop Prospects').first().json;

// Extract reviews for pain point analysis
const reviews = details.reviews || [];
const recentReviews = reviews.slice(0, 5);

// Analyze reviews for pain points
const painPoints = [];
const positives = [];

const painKeywords = [
  { keyword: 'never called back', pain: 'communication' },
  { keyword: 'didn\'t answer', pain: 'missed_calls' },
  { keyword: 'waited forever', pain: 'response_time' },
  { keyword: 'no one answered', pain: 'missed_calls' },
  { keyword: 'hard to reach', pain: 'communication' },
  { keyword: 'couldn\'t get through', pain: 'missed_calls' },
  { keyword: 'left voicemail', pain: 'missed_calls' },
  { keyword: 'took days', pain: 'response_time' },
  { keyword: 'scheduling', pain: 'scheduling' },
  { keyword: 'appointment', pain: 'scheduling' },
  { keyword: 'expensive', pain: 'pricing_objections' },
  { keyword: 'overpriced', pain: 'pricing_objections' }
];

recentReviews.forEach(review => {
  const text = (review.text || '').toLowerCase();
  const rating = review.rating || 5;

  if (rating <= 3) {
    painKeywords.forEach(pk => {
      if (text.includes(pk.keyword) && !painPoints.includes(pk.pain)) {
        painPoints.push(pk.pain);
      }
    });
  }
});

// Calculate outreach priority
let outreachPriority = prospectData.prospectScore;

// Boost if they have communication pain points (our solution!)
if (painPoints.includes('missed_calls')) outreachPriority += 20;
if (painPoints.includes('response_time')) outreachPriority += 15;
if (painPoints.includes('communication')) outreachPriority += 10;

// Extract domain from website for email guessing
let domain = null;
let possibleEmails = [];

if (details.website) {
  try {
    const url = new URL(details.website);
    domain = url.hostname.replace('www.', '');

    // Common email patterns
    possibleEmails = [
      `info@${domain}`,
      `contact@${domain}`,
      `service@${domain}`,
      `office@${domain}`
    ];
  } catch (e) {}
}

return {
  json: {
    // Basic info
    name: details.name || prospectData.name,
    phone: details.formatted_phone_number || null,
    website: details.website || null,
    domain: domain,
    address: details.formatted_address || prospectData.address,
    googleMapsUrl: details.url || null,

    // Scoring
    rating: prospectData.rating,
    reviewCount: prospectData.reviewCount,
    prospectScore: prospectData.prospectScore,
    outreachPriority: Math.min(100, outreachPriority),

    // Pain points (GOLD for personalization)
    painPoints: painPoints,
    hasCommunicationPain: painPoints.includes('missed_calls') || painPoints.includes('communication'),
    hasResponseTimePain: painPoints.includes('response_time'),

    // Contact guesses
    possibleEmails: possibleEmails,

    // Sample negative reviews (for outreach personalization)
    negativeReviewSnippets: recentReviews
      .filter(r => r.rating <= 3)
      .slice(0, 2)
      .map(r => r.text?.substring(0, 200)),

    // Meta
    city: prospectData.city,
    state: prospectData.state,
    scrapedAt: new Date().toISOString(),
    status: 'scraped',
    outreachStatus: 'pending'
  }
};

// Daily summary
const allProspects = $('Enrich & Analyze').all();
const cityData = $('Get Target City').first().json;

const summary = {
  date: new Date().toISOString(),
  city: cityData.city,
  state: cityData.state,
  totalFound: allProspects.length,
  highPriority: allProspects.filter(p => p.json.outreachPriority >= 80).length,
  withCommunicationPain: allProspects.filter(p => p.json.hasCommunicationPain).length,
  averageScore: Math.round(allProspects.reduce((sum, p) => sum + p.json.prospectScore, 0) / allProspects.length)
};

return { json: summary };

